library(shiny)
library(readxl)
# ====== 1. 安全隨機函數 ======
resample <- function(x, ...) {
  if (length(x) <= 1) x else sample(x, ...)
}

# ====== 2. CSS 樣式修正 (強制內部捲軸) ======
style <- "
  .flashcard-container {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 620px; /* 固定容器高度 */
    margin-bottom: 20px;
    width: 100%;
  }
  .flashcard-btn {
    width: 100%;
    max-width: 800px;
    height: 600px; /* 固定卡片高度 */
    background-color: #ffffff;
    border: 2px solid #dee2e6;
    border-radius: 20px;
    box-shadow: 0 6px 12px rgba(0,0,0,0.1);
    color: #333;
    padding: 0;
    display: flex;
    flex-direction: column;
    overflow: hidden; /* 防止內容溢出卡片邊框 */
  }
  .card-status-hint {
    font-size: 13px;
    font-weight: bold;
    color: #aaa;
    padding: 15px 0 5px 0;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    text-align: center;
    width: 100%;
    background: white;
    flex-shrink: 0;
    border-bottom: 1px solid #f8f9fa;
  }
  .card-content-wrapper {
    flex: 1; /* 佔滿剩餘高度 */
    display: flex;
    flex-direction: column;

    align-items: center;
    overflow-y: auto; /* 強制開啟垂直捲軸 */
    width: 100%;
    padding: 0 45px;
    /* 修正捲軸在 iOS/iPad 上的順滑度 */
    -webkit-overflow-scrolling: touch; 
    max-height: 580px;
    font-size: 20px;
    font-weight: bold;
    line-height: 1.5;
    white-space: pre-wrap; 
    word-wrap: break-word;
  }
  .inner-content {
    margin: auto 0; /* 短文字垂直置中 */
    width: 100%;
    text-align: left;
    padding: 30px 0;
    font-size: 15px;
    font-weight: bold;
    line-height: 1.6;
    white-space: pre-wrap; 
    word-wrap: break-word;
    color: inherit;
    /* 關鍵：當內容長過容器時，確保從頂部開始排版 */
    min-height: min-content; 
  }
  .btn-group-container {
    display: flex;
    justify-content: center;
    gap: 12px;
    margin-top: 10px;
  }
  .status-btn { 
    width: 100%; 
    max-width: 130px; 
    font-size: 16px; 
    padding: 12px; 
    border-radius: 10px; 
    font-weight: bold;
  }
  .control-panel {
    margin-top: 20px;
    padding: 20px;
    background-color: #fcfcfc;
    border-radius: 15px;
    border: 1px solid #eee;
  }
"

# ====== 3. UI 介面 (結構調整) ======
ui <- fluidPage(
  tags$head(
    tags$style(HTML(style)),
    tags$meta(name="viewport", content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no")
  ),
  titlePanel("Flashcards"),
  
  tabsetPanel(
    tabPanel("主學習模式",
             br(),
             div(class = "control-panel",
                 fileInput("upload_file", "📁 步驟 1：選擇 Excel 題庫",
                           accept = c(".xlsx"), buttonLabel = "瀏覽...")
             ),
             
             div(class = "flashcard-container",
                 # 將按鈕設為 div 包裹，避免 actionButton 預設的垂直置中干擾
                 tags$button(id = "flip", class = "flashcard-btn action-button",
                             uiOutput("card_content")
                 )
             ),
             
             div(class = "btn-group-container",
                 actionButton("again", "不會", class = "btn-danger status-btn"),
                 actionButton("hard", "不熟", class = "btn-warning status-btn"),
                 actionButton("good", "會了", class = "btn-success status-btn")
             ),
             hr(),
             actionButton("restart", "🔄 重新開始", class = "btn-default btn-block"),
             h4(textOutput("progress"), style="text-align:center; margin-top: 20px; color: #888;")
    ),
    
    tabPanel("錯題複習模式",
             br(),
             div(class = "flashcard-container",
                 tags$button(id = "flip2", class = "flashcard-btn action-button",
                             uiOutput("review_card_content")
                 )
             ),
             div(class = "btn-group-container",
                 actionButton("next_w", "下一個", class = "btn-warning status-btn"),
                 actionButton("good2", "移除錯題", class = "btn-success status-btn")
             ),
             hr(),
             actionButton("restart_review", "🚀 開始複習", class = "btn-lg btn-block btn-primary"),
             h4(textOutput("review_progress"), style="text-align:center; margin-top: 20px; color: #888;")
    )
  )
)

# ====== 4. Server 邏輯 ======
server <- function(input, output, session) {
  
  cards <- reactiveVal(data.frame(id=integer(), front=character(), back=character()))
  wrong_ids <- reactiveVal(c())
  order <- reactiveVal(NULL)
  index <- reactiveVal(1)
  show_answer <- reactiveVal(FALSE)
  
  review_order <- reactiveVal(NULL)
  review_index <- reactiveVal(1)
  show_answer2 <- reactiveVal(FALSE)
  
  observeEvent(input$upload_file, {
    req(input$upload_file)
    tryCatch({
      raw <- read_excel(input$upload_file$datapath)
      smart_split <- function(x) {
        x <- as.character(x)
        x <- gsub("\r\n|\n", "<br>", x)
        target_symbols <- "➢|◼|□|✅|●|○|•|❑|▲|▼|※|◆|⚫"
        x <- gsub(paste0("(?=", target_symbols, ")"), "<br>", x, perl=TRUE)
        x <- gsub("(<br>\\s*)+", "<br>", x)
        x <- gsub("^<br>|<br>$", "", x)
        return(x)
      }
      df <- data.frame(id = 1:nrow(raw), front = smart_split(raw[[1]]), back = smart_split(raw[[2]]), stringsAsFactors = FALSE)
      cards(df); wrong_ids(c()); order(resample(df$id)); index(1); show_answer(FALSE)
    }, error = function(e) { showNotification("讀取失敗", type = "error") })
  })
  
  # 渲染主內容
  render_card <- function(is_review = FALSE) {
    df <- cards()
    ord <- if(is_review) review_order() else order()
    idx <- if(is_review) review_index() else index()
    show_ans <- if(is_review) show_answer2() else show_answer()
    
    if (is.null(ord) || nrow(df) == 0) return(div(class="card-content-wrapper", div(class="inner-content", style="text-align:center;", "請先上傳檔案")))
    if (idx > length(ord)) return(div(class="card-content-wrapper", div(class="inner-content", style="text-align:center;color:green;", "🎉 已完成！")))
    
    row <- df[df$id == ord[idx], ]
    color <- if(!show_ans) "#333" else (if(is_review) "#dc3545" else "#007bff")
    txt <- if(!show_ans) row$front else row$back
    label <- if(!show_ans) "QUESTION" else "ANSWER (Scroll to read)"
    
    tagList(
      div(class="card-status-hint", label),
      div(class="card-content-wrapper",
          div(class="inner-content", style = paste0("color:", color, ";"), HTML(txt))
      )
    )
  }
  
  output$card_content <- renderUI({ render_card(FALSE) })
  output$review_card_content <- renderUI({ render_card(TRUE) })
  
  observeEvent(input$flip, { show_answer(!show_answer()) })
  observeEvent(input$flip2, { show_answer2(!show_answer2()) })
  
  process_main <- function(res) {
    if (is.null(order()) || index() > length(order())) return()
    if (res != "會") wrong_ids(unique(c(wrong_ids(), order()[index()])))
    index(index() + 1); show_answer(FALSE)
  }
  
  observeEvent(input$again, { process_main("不會") })
  observeEvent(input$hard, { process_main("不熟") })
  observeEvent(input$good, { process_main("會") })
  observeEvent(input$restart, { if(nrow(cards()) > 0) { order(resample(cards()$id)); index(1); show_answer(FALSE) } })
  output$progress <- renderText({ if (is.null(order())) "" else paste0("進度：", min(index(), length(order())), " / ", length(order())) })
  
  observeEvent(input$good2, { if (review_index() <= length(review_order())) { wrong_ids(setdiff(wrong_ids(), review_order()[review_index()])); review_index(review_index() + 1); show_answer2(FALSE) } })
  observeEvent(input$next_w, { if (review_index() <= length(review_order())) { review_index(review_index() + 1); show_answer2(FALSE) } })
  observeEvent(input$restart_review, { if (length(wrong_ids()) > 0) { review_order(resample(wrong_ids())); review_index(1); show_answer2(FALSE) } })
  output$review_progress <- renderText({ paste0("目前待複習總數：", length(wrong_ids())) })
}

shinyApp(ui, server)

